import React, { useState } from 'react';
import { UserRole, User } from '../types';
import { Box, User as UserIcon, ShieldCheck, Mail, Lock, ArrowRight, Loader2 } from 'lucide-react';

interface AuthProps {
  onLogin: (user: User) => void;
}

export const Auth: React.FC<AuthProps> = ({ onLogin }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [role, setRole] = useState<UserRole>(UserRole.CUSTOMER);
  const [isLoading, setIsLoading] = useState(false);
  const [email, setEmail] = useState('');
  const [name, setName] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);

    // Simulate API delay
    setTimeout(() => {
      onLogin({
        id: Math.random().toString(36).substr(2, 9),
        name: isLogin ? (role === UserRole.ADMIN ? 'Adam' : 'Sufiyan') : name,
        email: email,
        role: role
      });
      setIsLoading(false);
    }, 1500);
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-50 p-6 relative overflow-hidden">
      {/* Decorative blobs */}
      <div className="absolute top-0 -left-20 w-96 h-96 bg-indigo-100 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-pulse"></div>
      <div className="absolute -bottom-20 -right-20 w-96 h-96 bg-violet-100 rounded-full mix-blend-multiply filter blur-3xl opacity-30 animate-pulse delay-700"></div>

      <div className="w-full max-w-md z-10">
        <div className="flex flex-col items-center mb-10 transform transition-all duration-700 ease-out translate-y-0 opacity-100">
          <div className="bg-indigo-600 p-3 rounded-2xl text-white shadow-xl shadow-indigo-200 mb-4 animate-bounce">
            <Box size={32} />
          </div>
          <h1 className="text-3xl font-bold text-slate-900 tracking-tight">RentFlow Pro</h1>
          <p className="text-slate-500 mt-2">The future of rental management</p>
        </div>

        <div className="bg-white rounded-[2.5rem] shadow-2xl shadow-slate-200/60 p-10 border border-slate-100 transform transition-all hover:scale-[1.01]">
          {/* Role Toggle */}
          <div className="flex p-1 bg-slate-100 rounded-2xl mb-8 relative">
            <div 
              className={`absolute top-1 bottom-1 w-[48%] bg-white rounded-xl shadow-sm transition-all duration-300 ease-out ${role === UserRole.ADMIN ? 'left-[51%]' : 'left-1'}`}
            ></div>
            <button 
              onClick={() => setRole(UserRole.CUSTOMER)}
              className={`flex-1 relative z-10 py-2.5 text-sm font-bold flex items-center justify-center gap-2 transition-colors ${role === UserRole.CUSTOMER ? 'text-indigo-600' : 'text-slate-500'}`}
            >
              <UserIcon size={16} /> Customer
            </button>
            <button 
              onClick={() => setRole(UserRole.ADMIN)}
              className={`flex-1 relative z-10 py-2.5 text-sm font-bold flex items-center justify-center gap-2 transition-colors ${role === UserRole.ADMIN ? 'text-indigo-600' : 'text-slate-500'}`}
            >
              <ShieldCheck size={16} /> Admin
            </button>
          </div>

          <h2 className="text-xl font-bold text-slate-800 mb-6 text-center">
            {isLogin ? `Log in as ${role === UserRole.ADMIN ? 'Admin' : 'Customer'}` : `Create ${role === UserRole.ADMIN ? 'Admin' : 'Customer'} Account`}
          </h2>

          <form onSubmit={handleSubmit} className="space-y-5">
            {!isLogin && (
              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-wider ml-1">Full Name</label>
                <div className="relative">
                  <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                  <input 
                    required
                    type="text" 
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    placeholder="John Doe" 
                    className="w-full pl-12 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all text-sm"
                  />
                </div>
              </div>
            )}
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-wider ml-1">Email Address</label>
              <div className="relative">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                  required
                  type="email" 
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="name@company.com" 
                  className="w-full pl-12 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all text-sm"
                />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-400 uppercase tracking-wider ml-1">Password</label>
              <div className="relative">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
                <input 
                  required
                  type="password" 
                  placeholder="••••••••" 
                  className="w-full pl-12 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all text-sm"
                />
